const fibonacciCompiledDart = r'''
// Generated by ball compiler
// Source: fibonacci v1.0.0
// Target: Dart

int fibonacci(int n) {
  if ((n <= 1)) {
    return n;
  }
  return (fibonacci((n - 1)) + fibonacci((n - 2)));
}

void main() {
  final result = fibonacci(10);
  print(result.toString());
}
''';

